<?php
 namespace WPAICG\Chat\Storage\SaverMethods; use WPAICG\Chat\Storage\SiteWideBotManager; use WP_Error; require_once __DIR__ . '/validate-bot-post-logic.php'; require_once __DIR__ . '/sanitize-settings-logic.php'; require_once __DIR__ . '/handle-site-wide-logic.php'; require_once __DIR__ . '/save-meta-fields-logic.php'; require_once __DIR__ . '/handle-openai-specific-settings-logic.php'; if (!defined('ABSPATH')) { exit; } function save_bot_settings_logic(int $botId, array $raw_settings, SiteWideBotManager $site_wide_manager): bool|WP_Error { $validation_result = validate_bot_post_logic($botId); if (is_wp_error($validation_result)) { return $validation_result; } $sanitized_settings = sanitize_settings_logic($raw_settings, $botId); $should_clear_site_wide_cache = handle_site_wide_logic( $site_wide_manager, $botId, $sanitized_settings['site_wide_enabled'] ); $meta_save_result = save_meta_fields_logic($botId, $sanitized_settings); if (is_wp_error($meta_save_result)) { return $meta_save_result; } handle_openai_specific_settings_logic($botId, $sanitized_settings); if ($should_clear_site_wide_cache) { $site_wide_manager->clear_site_wide_cache(); } do_action('aipkit_after_bot_settings_saved', $botId, $sanitized_settings); return true; } 